from dataclasses import dataclass

@dataclass
class GenerationParams:
    temperature: float
    max_tokens: int
    top_p: float = 1.0

    def __post_init__(self) -> None:
        if not 0.0 <= self.temperature <= 2.0:
            raise ValueError(f"temperature {self.temperature!r} must be in [0, 2]")
        if self.max_tokens < 1:
            raise ValueError("max_tokens must be positive")
        if not 0.0 < self.top_p <= 1.0:
            raise ValueError("top_p must be in (0, 1]")

# Raises ValueError immediately — no silent corruption
try:
    params = GenerationParams(temperature=3.5, max_tokens=1024)
except ValueError as e:
    print(e)  # temperature 3.5 must be in [0, 2]

from __future__ import annotations
from dataclasses import dataclass, field, asdict
from typing import Any
import time
import json

# ── Shared message record ───────────────────────────────────────────────────

@dataclass
class Message:
    role: str          # "system" | "user" | "assistant" | "tool"
    content: str
    tool_call_id: str | None = None

# ── Mutable agent state (accumulates messages during a run) ─────────────────

@dataclass
class AgentState:
    run_id: str
    model: str = "gpt-4o"
    messages: list[Message] = field(default_factory=list)
    token_counts: dict[str, int] = field(default_factory=dict)
    started_at: float = field(default_factory=time.time)
    finished_at: float | None = None

    def push(self, role: str, content: str, **kw: Any) -> None:
        self.messages.append(Message(role=role, content=content, **kw))

    def finish(self) -> None:
        self.finished_at = time.time()

    def elapsed_ms(self) -> float | None:
        if self.finished_at is None:
            return None
        return (self.finished_at - self.started_at) * 1000

# ── Immutable tool-call record ──────────────────────────────────────────────

@dataclass(frozen=True)
class ToolCall:
    name: str
    arguments: dict[str, Any]
    call_id: str

    @classmethod
    def from_dict(cls, data: dict[str, Any]) -> ToolCall:
        return cls(
            name=data["name"],
            arguments=data.get("arguments") or {},
            call_id=data["id"],
        )

# ── Usage ──────────────────────────────────────────────────────────────────

state = AgentState(run_id="run-001")
state.push("user", "What is the capital of France?")

raw = {"name": "web_search", "arguments": {"q": "capital France"}, "id": "c-42"}
tc = ToolCall.from_dict(raw)

# Serialize back to dict / JSON
print(json.dumps(asdict(state), default=str))

from dataclasses import dataclass, field, asdict
from typing import Any, Callable
import json

# ── Types ──────────────────────────────────────────────────────────────────

@dataclass(frozen=True)
class ToolCall:
    id:        str
    name:      str
    arguments: dict[str, Any]

@dataclass
class ToolResult:
    call_id:  str
    name:     str
    output:   Any
    error:    str | None = None
    is_error: bool = False

    @classmethod
    def from_exception(cls, call: ToolCall, exc: Exception) -> "ToolResult":
        return cls(
            call_id=call.id, name=call.name,
            output=None, error=str(exc), is_error=True,
        )

# ── Dispatcher ─────────────────────────────────────────────────────────────

Registry = dict[str, Callable[..., Any]]

def dispatch(call: ToolCall, registry: Registry) -> ToolResult:
    handler = registry.get(call.name)
    if handler is None:
        return ToolResult(
            call_id=call.id, name=call.name, output=None,
            error=f"unknown tool '{call.name}'", is_error=True,
        )
    try:
        output = handler(**call.arguments)
        return ToolResult(call_id=call.id, name=call.name, output=output)
    except Exception as exc:
        return ToolResult.from_exception(call, exc)

# ── Wire-up ────────────────────────────────────────────────────────────────

def web_search(q: str, max_results: int = 5) -> list[str]:
    return [f"Result {i} for '{q}'" for i in range(max_results)]

TOOLS: Registry = {"web_search": web_search}

raw_calls = [
    {"id": "c-1", "name": "web_search", "arguments": {"q": "agents", "max_results": 3}},
    {"id": "c-2", "name": "missing_tool", "arguments": {}},
]

results = []
for raw in raw_calls:
    call = ToolCall(**{k: raw[k] for k in ("id", "name", "arguments")})
    result = dispatch(call, TOOLS)
    results.append(result)
    print(f"[{'OK' if not result.is_error else 'ERR'}] {result.name}: {result.output or result.error}")

# Convert to JSON for the next LLM turn
tool_messages = [
    {"role": "tool", "tool_call_id": r.call_id, "content": json.dumps(r.output)}
    for r in results if not r.is_error
]

from dataclasses import dataclass

@dataclass
class Base:
    x: int = 0  # has a default

# This fails at class definition — 'y' (required) would follow 'x' (optional)
# @dataclass
# class Child(Base):
#     y: int  # TypeError!

# Correct: give child field a default, or use composition
@dataclass
class ChildOK(Base):
    y: int = 1

@dataclass
class Composed:
    base: Base
    y: int  # now required first, then Base fields are separate

from dataclasses import dataclass, field

@dataclass(frozen=True)
class Footgun:
    items: list = field(default_factory=list)

f = Footgun()
# f.items = []  -> FrozenInstanceError (prevented)
f.items.append("oops")  # No error — the list itself is still mutable!
print(f.items)  # ['oops']

# Fix: use tuple instead of list for truly immutable containers
@dataclass(frozen=True)
class Safe:
    items: tuple[str, ...] = ()

from dataclasses import dataclass
from typing import Any

@dataclass(frozen=True)
class ToolCall:
    name: str
    arguments: dict[str, Any]
    call_id: str

    @classmethod
    def from_raw(cls, raw: dict[str, Any]) -> "ToolCall":
        for key in ("name", "id"):
            if key not in raw:
                raise ValueError(f"ToolCall missing required key: {key!r}")
        name = raw["name"]
        if not isinstance(name, str) or not name:
            raise ValueError(f"ToolCall.name must be a non-empty string, got {name!r}")
        arguments = raw.get("arguments") or {}
        if not isinstance(arguments, dict):
            raise ValueError(f"ToolCall.arguments must be a dict, got {type(arguments)}")
        return cls(name=name, arguments=arguments, call_id=raw["id"])

# Safe construction
raw = {"name": "web_search", "arguments": {"q": "test"}, "id": "c-1"}
tc = ToolCall.from_raw(raw)
